css:
body {
  font-family: 'EB Garamond', serif;
  font-size: 11pt;
  color: #1a1a1a;
  background: #fff;
  line-height: 1.6;
}

.page {
  width: 100%;
  box-sizing: border-box;
}


/* ── COMPANY LOGO ── */
.company-logo {
  height: 52px;
  width: auto;
  object-fit: contain;
  display: block;
  margin-bottom: 6px;
}
.logo-placeholder {
  font-family: 'Montserrat', sans-serif;
  font-size: 9pt;
  font-weight: 700;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: #aaa;
  border: 1.5px dashed #ccc;
  padding: 6px 14px;
  display: inline-block;
  margin-bottom: 6px;
}

/* ── HEADER ── */
.doc-header {
  border-bottom: 2.5px solid #1a1a1a;
  padding-bottom: 10px;
  margin-bottom: 20px;
}
.company-name {
  font-family: 'Montserrat', sans-serif;
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #555;
}
.doc-title {
  font-family: 'EB Garamond', serif;
  font-size: 26pt;
  font-weight: 600;
  line-height: 1.1;
  color: #1a1a1a;
}
.doc-meta {
  text-align: right;
  font-family: 'Montserrat', sans-serif;
  font-size: 8pt;
  color: #555;
  line-height: 2;
  max-width: 45%;
  word-break: break-word;
}
.doc-meta .doc-id {
  font-weight: 700;
  font-size: 9.5pt;
  color: #1a1a1a;
  letter-spacing: 0.04em;
  display: block;
}
.status-badge {
  font-family: 'Montserrat', sans-serif;
  font-size: 7pt;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  border: 1.5px solid #1a1a1a;
  padding: 2px 9px;
  color: #1a1a1a;
  display: inline-block;
  margin-top: 4px;
}

/* ── SECTION LABEL ── */
.section-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 7.5pt;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #555;
  margin: 20px 0 8px 0;
  padding-bottom: 5px;
  border-bottom: 1px solid #ccc;
}

/* ── EMPLOYEE DETAILS TABLE ── */
.emp-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 4px;
}
.emp-table th {
  font-family: 'Montserrat', sans-serif;
  font-size: 7.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: #fff;
  background: #1a1a1a;
  padding: 6px 10px;
  border: 1px solid #1a1a1a;
  white-space: nowrap;
  vertical-align: middle;
}
.emp-table td {
  font-size: 10.5pt;
  color: #1a1a1a;
  padding: 7px 10px;
  border: 1px solid #ddd;
  vertical-align: middle;
}
.emp-table tr:nth-child(even) td { background: #fafafa; }

/* ── RATING TABLE ── */
.rating-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 4px;
}
.rating-table thead th {
  font-family: 'Montserrat', sans-serif;
  font-size: 7.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: #fff;
  background: #1a1a1a;
  padding: 7px 10px;
  border: 1px solid #1a1a1a;
}
.rating-table tbody td {
  padding: 7px 10px;
  border: 1px solid #ddd;
  font-size: 10.5pt;
  vertical-align: middle;
}
.rating-table tbody tr:nth-child(even) td { background: #fafafa; }
.rating-table .rating-val {
  text-align: center;
  font-family: 'Montserrat', sans-serif;
  font-weight: 700;
  font-size: 11pt;
}
.rating-table .comment-val {
  font-style: italic;
  color: #444;
  font-size: 10pt;
}

/* ── Q&A TABLE ── */
.qa-table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 4px;
}
.qa-table td {
  padding: 7px 10px;
  border: 1px solid #ddd;
  vertical-align: top;
  font-size: 10.5pt;
}
.qa-table .q-cell {
  font-family: 'Montserrat', sans-serif;
  font-size: 8pt;
  font-weight: 600;
  color: #333;
  background: #f5f5f5;
  width: 36%;
  line-height: 1.5;
}
.qa-table .a-cell { color: #1a1a1a; }
.qa-table .a-cell p, .qa-table .a-cell span { font-size: 10.5pt; }

/* ── SIGNATURE ── */
.sig-section {
  margin-top: 28px;
  border-top: 1px solid #ccc;
  padding-top: 16px;
}
.sig-line {
  border-bottom: 1px solid #1a1a1a;
  height: 30px;
  margin-bottom: 5px;
}
.sig-meta {
  font-family: 'Montserrat', sans-serif;
  font-size: 7.5pt;
  color: #666;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ── FOOTER ── */
.doc-footer {
  margin-top: 22px;
  border-top: 1px solid #e0e0e0;
  padding-top: 8px;
}
.footer-text {
  font-family: 'Montserrat', sans-serif;
  font-size: 7pt;
  color: #aaa;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

@media print {
  body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
}
